// Unit 14. Le futur
// Future Tense: Proche & Simple

export default {n:14,lang:"fr",srcLang:"en",track:"v2",title:"Le futur",sub:"Future Tense: Proche & Simple",icon:"🔮",level:"A2.6",color:"#7B5EE8",lessons:[
  {id:"fre14l1",title:"Le futur proche",icon:"⏰",xp:15,board:true,steps:[
        {type:"intro",title:"The near future: aller + infinitive",desc:"The easiest way to talk about the future in French! Just use the present tense of aller (to go) + any infinitive. This works just like English 'going to'.",goals:["Form futur proche with aller + infinitive","Talk about plans and intentions","Use futur proche in negative sentences"]},
        {type:"tip",title:"Futur proche formula",text:"aller (conjugated) + INFINITIVE\n\nje vais manger = I'm going to eat\ntu vas partir = you're going to leave\nil/elle va travailler = he/she is going to work\nnous allons voyager = we're going to travel\nvous allez comprendre = you're going to understand\nils/elles vont arriver = they're going to arrive\n\nNegative: subject + ne + aller + pas + infinitive\nJe ne vais pas manger. (I'm not going to eat.)"},
        {type:"teach",trg:"Je vais manger.",src:"I'm going to eat.",pos:"verb",gender:null,phonetic:"zhuh vay mahn-ZHAY",note:"Futur proche: je vais + infinitive.\nExpresses plans and near-future actions.\nVery common in spoken French.",example:"A: Tu as faim?\nB: Oui! Je vais manger dans cinq minutes.\nA: Bon appétit!",exampleSrc:"A: Are you hungry?\nB: Yes! I'm going to eat in five minutes.\nA: Enjoy your meal!",funFact:"I am going to eat. Near future: aller + infinitive. Spoken-French default future."},
        {type:"teach",trg:"Nous allons voyager.",src:"We're going to travel.",pos:"verb",gender:null,phonetic:"nooz ah-LON vwah-yah-ZHAY",note:"Nous allons + infinitive.\nAllons = nous form of aller.\nUsed for plans and intentions.",example:"A: Qu'est-ce que vous allez faire cet été?\nB: Nous allons voyager en Italie!\nA: Quelle chance!",exampleSrc:"A: What are you going to do this summer?\nB: We're going to travel to Italy!\nA: How lucky!",funFact:"We are going to travel. Same near-future structure with nous."},
        {type:"teach",trg:"Il va pleuvoir.",src:"It's going to rain.",pos:"verb",gender:null,phonetic:"eel vah pluh-VWAR",note:"Il va + infinitive for weather predictions.\nVa = il/elle form of aller.\nUsed when you see evidence of what's coming.",example:"A: Tu prends un parapluie?\nB: Oui, regarde le ciel. Il va pleuvoir.\nA: Bonne idée!",exampleSrc:"A: Are you taking an umbrella?\nB: Yes, look at the sky. It's going to rain.\nA: Good idea!",funFact:"It is going to rain. Weather + near-future. Pleuvoir irregular."},
        {type:"mc",q:"To form the futur proche, use:",opts:["Aller + infinitive","Être + past participle","Avoir + past participle","Venir + infinitive"],ans:"Aller + infinitive",hint:"Going to do something = go verb + action verb in base form."},
        {type:"fb",opts:["vas","vais","va","allez"],hint:"You're going to leave tomorrow? Tu + which form of aller?",s:"Tu {1} partir demain? (going to)",a:"vas"},
        {type:"mc",q:"'Elles ___ arriver à midi.' (going to)",opts:["Vas","Vont","Va","Allez"],ans:"Vont",hint:"They (feminine plural) + which form of aller?"},
        {type:"fb",opts:["vais","vas","va","allons"],hint:"I'm not going to work. Ne + aller + pas + infinitive.",s:"Je ne {1} pas travailler ce week-end. (going to)",a:"vais"},
        {type:"match",pairs:[{trg:"je vais",src:"I'm going to"},{trg:"tu vas",src:"you're going to"},{trg:"nous allons",src:"we're going to"},{trg:"ils vont",src:"they're going to"}]},
        {type:"mc",q:"The futur proche is used for:",opts:["Distant future plans","Past events","Near future / intentions","Habitual actions"],ans:"Near future / intentions",hint:"Something you're about to do or planning to do soon."},
        {type:"fb",opts:["allez","allons","vont","vas"],hint:"You're going to love this film! Vous + which form?",s:"Vous {1} adorer ce film! (going to)",a:"allez"},
        {type:"mc",q:"'On va manger.' Why is manger in the infinitive?",opts:["Because it's the past","Because of negation","Because it's a question","Because aller is already conjugated"],ans:"Because aller is already conjugated",hint:"Only one verb gets ___. The action verb stays in base form."},
        {type:"fb",opts:["allons","allez","vont","vais"],hint:"We're going to move in March. Nous + aller.",s:"Nous {1} déménager en mars. (going to)",a:"allons"},
        {type:"match",pairs:[{trg:"Je vais manger",src:"I'm going to eat"},{trg:"Elle va chanter",src:"She's going to sing"},{trg:"Ils vont dormir",src:"They're going to sleep"},{trg:"Vous allez voir",src:"You're going to see"}]},
        {type:"mc",q:"Negative futur proche: 'Il ___ travailler.'",opts:["ne va pas","ne pas va","pas ne va","va ne pas"],ans:"ne va pas",hint:"The two negative elements wrap around the conjugated verb, not the infinitive."},
        {type:"fb",opts:["va","vais","vas","vont"],hint:"She's going to have a baby! Third person singular of aller.",s:"Elle {1} avoir un bébé! (going to)",a:"va"},
        {type:"mc",q:"Which expresses an immediate action?",opts:["J'ai mangé","Je vais manger","Je mangeais","Je mangerai"],ans:"Je vais manger",hint:"Going to eat = something about to happen very soon."}
  ]},
  {id:"fre14l2",title:"Le futur simple",icon:"🔭",xp:15,board:true,steps:[
        {type:"intro",title:"The simple future tense",desc:"The futur simple is a single-word future tense. For regular verbs, add future endings to the infinitive. It sounds more formal and is used for predictions and promises.",goals:["Form futur simple for regular -er, -ir, -re verbs","Learn the future endings","Distinguish futur proche from futur simple"]},
        {type:"tip",title:"Futur simple formation",text:"REGULAR -er/-ir: infinitive + endings\nparler: je parlerai, tu parleras...\nfinir: je finirai, tu finiras...\n\nREGULAR -re: drop final -e + endings\nprendre: je prendrai, tu prendras...\n\nENDINGS (same for ALL verbs):\nje: -ai\ntu: -as\nil/elle/on: -a\nnous: -ons\nvous: -ez\nils/elles: -ont\n\nNote: endings look like avoir present!\n(ai, as, a, ons, ez, ont)"},
        {type:"teach",trg:"je parlerai",src:"I will speak",pos:"verb",gender:null,phonetic:"zhuh par-luh-RAY",note:"Futur simple of parler.\nInfinitive (parler) + -ai = parlerai.\nUsed for predictions and promises.",example:"A: Tu parles français?\nB: Un peu. Mais je parlerai mieux dans un an!\nA: J'en suis sûr!",exampleSrc:"A: Do you speak French?\nB: A little. But I will speak better in a year!\nA: I'm sure of it!",funFact:"I will speak. Simple future. -er verb adds -erai to infinitive. More formal/written than aller+inf."},
        {type:"teach",trg:"nous finirons",src:"we will finish",pos:"verb",gender:null,phonetic:"noo fee-nee-RON",note:"Futur simple of finir.\nInfinitive (finir) + -ons = finirons.\nAll -ir verbs follow this pattern.",example:"A: Quand est-ce que vous finirez le projet?\nB: Nous finirons vendredi.\nA: Parfait!",exampleSrc:"A: When will you finish the project?\nB: We will finish on Friday.\nA: Perfect!",funFact:"We will finish. -ir verb future. Nous adds -ons to future stem."},
        {type:"teach",trg:"il prendra",src:"he will take",pos:"verb",gender:null,phonetic:"eel prahn-DRAH",note:"Futur simple of prendre.\nDrop final -e: prendr- + -a = prendra.\nAll -re verbs drop the final -e.",example:"A: Pierre prend le train ou l'avion?\nB: Il prendra l'avion, c'est plus rapide.\nA: Bonne idée.",exampleSrc:"A: Is Pierre taking the train or the plane?\nB: He will take the plane, it's faster.\nA: Good idea.",funFact:"He will take. Irregular future of prendre. Stem: prendr- + a."},
        {type:"mc",q:"Futur simple of -er verbs: infinitive + endings. 'Manger' -> je ___:",opts:["Mangerai","Mangeai","Mangerais","Mange"],ans:"Mangerai",hint:"Infinitive (manger) + -ai ending = future form for je."},
        {type:"fb",opts:["partiras","pars","es parti","partais"],hint:"You will leave tomorrow. Infinitive + -as (tu ending).",s:"Tu {1} demain matin. (partir, futur simple)",a:"partiras"},
        {type:"mc",q:"The futur simple endings resemble the present tense of:",opts:["Être","Avoir","Aller","Faire"],ans:"Avoir",hint:"The endings -ai, -as, -a, -ons, -ez, -ont match this verb."},
        {type:"fb",opts:["mangerons","mangeons","avons mangé","mangions"],hint:"We will eat together tonight. Infinitive + -ons.",s:"Nous {1} ensemble ce soir. (manger, futur simple)",a:"mangerons"},
        {type:"match",pairs:[{trg:"je -ai",src:"I will..."},{trg:"tu -as",src:"you will..."},{trg:"il/elle -a",src:"he/she will..."},{trg:"ils/elles -ont",src:"they will..."}]},
        {type:"mc",q:"For -re verbs, before adding endings you:",opts:["Add an extra -e","Double the last consonant","Drop the final -e","Change nothing"],ans:"Drop the final -e",hint:"Prendre -> prendr- + endings. Vendre -> vendr- + endings."},
        {type:"fb",opts:["regarderont","regardent","ont regardé","regardaient"],hint:"They will watch the game on TV. Infinitive + -ont.",s:"Ils {1} le match à la télé. (regarder, futur simple)",a:"regarderont"},
        {type:"mc",q:"Futur simple vs futur proche: 'Je vais manger' vs 'Je mangerai'. The futur simple sounds:",opts:["More casual","More past-like","More urgent","More formal or distant"],ans:"More formal or distant",hint:"Simple future is used for predictions, promises, and ___ speech."},
        {type:"fb",opts:["donnera","donne","a donné","donnait"],hint:"She will give the answer tomorrow. Infinitive + -a.",s:"Elle {1} la réponse demain. (donner, futur simple)",a:"donnera"},
        {type:"match",pairs:[{trg:"nous -ons",src:"we will..."},{trg:"vous -ez",src:"you will..."},{trg:"je parlerai",src:"I will speak"},{trg:"il finira",src:"he will finish"}]},
        {type:"mc",q:"'Vous ___ le contrat?' (signer, futur simple)",opts:["Signerez","Signez","Avez signé","Signiez"],ans:"Signerez",hint:"You will sign? Infinitive + -ez (vous)."},
        {type:"fb",opts:["discutera","discute","a discuté","discutait"],hint:"We'll discuss this question later. Infinitive + -a (on = il form).",s:"On {1} cette question plus tard. (discuter, futur simple)",a:"discutera"},
        {type:"mc",q:"Which is futur simple?",opts:["Je mange","Je mangerai","Je vais manger","Je mangeais"],ans:"Je mangerai",hint:"The single-word future with the -ai ending for je."}
  ]},
  {id:"fre14l3",title:"Les futurs irréguliers",icon:"⚡",xp:15,board:true,steps:[
        {type:"intro",title:"Irregular future stems",desc:"Some common verbs have irregular stems in the futur simple. The endings are always the same (-ai, -as, -a, -ons, -ez, -ont), only the stem changes.",goals:["Learn the 10 most important irregular stems","Conjugate être, avoir, aller, faire in the future","Recognize irregular patterns"]},
        {type:"tip",title:"Key irregular stems",text:"être -> ser-: je serai (I will be)\navoir -> aur-: j'aurai (I will have)\naller -> ir-: j'irai (I will go)\nfaire -> fer-: je ferai (I will do)\nvoir -> verr-: je verrai (I will see)\npouvoir -> pourr-: je pourrai (I will be able)\nvouloir -> voudr-: je voudrai (I will want)\nsavoir -> saur-: je saurai (I will know)\nvenir -> viendr-: je viendrai (I will come)\ndevoir -> devr-: je devrai (I will have to)\n\nEndings are ALWAYS regular: -ai, -as, -a, -ons, -ez, -ont"},
        {type:"teach",trg:"je serai",src:"I will be",pos:"verb",gender:null,phonetic:"zhuh suh-RAY",note:"Être -> stem: ser-\nJe serai, tu seras, il sera,\nnous serons, vous serez, ils seront.",example:"A: Où tu seras demain?\nB: Je serai au bureau.\nA: On se voit après le travail?",exampleSrc:"A: Where will you be tomorrow?\nB: I'll be at the office.\nA: Shall we meet after work?",funFact:"I will be. Irregular future of être. Stem ser- (not êtr-)."},
        {type:"teach",trg:"j'aurai",src:"I will have",pos:"verb",gender:null,phonetic:"zhoh-RAY",note:"Avoir -> stem: aur-\nJ'aurai, tu auras, il aura,\nnous aurons, vous aurez, ils auront.",example:"A: Tu auras le temps demain?\nB: Oui, j'aurai le temps après midi.\nA: Super!",exampleSrc:"A: Will you have time tomorrow?\nB: Yes, I'll have time after noon.\nA: Great!",funFact:"I will have. Simple future of avoir. Irregular stem aur-."},
        {type:"teach",trg:"j'irai",src:"I will go",pos:"verb",gender:null,phonetic:"zhee-RAY",note:"Aller -> stem: ir-\nJ'irai, tu iras, il ira,\nnous irons, vous irez, ils iront.",example:"A: Tu vas aller en France?\nB: Oui, j'irai en France l'été prochain.\nA: Tu visiteras Paris?",exampleSrc:"A: Are you going to France?\nB: Yes, I'll go to France next summer.\nA: Will you visit Paris?",funFact:"I will go. Simple future of aller. Irregular stem ir-."},
        {type:"mc",q:"The irregular future stem of faire is:",opts:["Fer-","Fair-","Fais-","Fait-"],ans:"Fer-",hint:"Je ___ai, tu ___as, il ___a. The stem has an -e- not -ai-."},
        {type:"fb",opts:["irons","allons","sommes allés","allions"],hint:"We will go on vacation in August. Irregular stem ir- + -ons.",s:"Nous {1} en vacances en août. (aller, futur simple)",a:"irons"},
        {type:"mc",q:"'Ils ___ le match demain.' (voir, futur simple)",opts:["Voiront","Verront","Voient","Vont voir"],ans:"Verront",hint:"Voir has a double-r stem. Verr- + -ont."},
        {type:"fb",opts:["pourras","peux","as pu","pouvais"],hint:"You will be able to whenever you want. Pourr- + -as.",s:"Tu {1} quand tu voudras. (pouvoir, futur simple)",a:"pourras"},
        {type:"match",pairs:[{trg:"être -> ser-",src:"je serai"},{trg:"avoir -> aur-",src:"j'aurai"},{trg:"aller -> ir-",src:"j'irai"},{trg:"faire -> fer-",src:"je ferai"}]},
        {type:"mc",q:"'Elle ___ la réponse demain.' (savoir, futur simple)",opts:["Savra","Saira","Saura","Savera"],ans:"Saura",hint:"Savoir -> stem saur-. Saur- + -a."},
        {type:"fb",opts:["viendrai","viens","suis venu","venais"],hint:"I will come see you. Venir -> viendr- + -ai.",s:"Je {1} te voir ce week-end. (venir, futur simple)",a:"viendrai"},
        {type:"mc",q:"Many irregular stems have a double consonant (verr-, pourr-). This helps with:",opts:["Grammar","Spelling only","Style","Pronunciation: the stem vowel stays short"],ans:"Pronunciation: the stem vowel stays short",hint:"The double -rr- keeps the preceding ___ ___ and clear."},
        {type:"fb",opts:["devrez","devez","avez dû","deviez"],hint:"You will have to work hard. Devoir -> devr- + -ez.",s:"Vous {1} travailler dur. (devoir, futur simple)",a:"devrez"},
        {type:"match",pairs:[{trg:"voir -> verr-",src:"je verrai"},{trg:"pouvoir -> pourr-",src:"je pourrai"},{trg:"venir -> viendr-",src:"je viendrai"},{trg:"devoir -> devr-",src:"je devrai"}]},
        {type:"mc",q:"The ENDINGS for irregular futures are:",opts:["The same regular endings as all verbs","Also irregular","Different for each verb","Only -ai for all persons"],ans:"The same regular endings as all verbs",hint:"Only the stem is ir___. ___ are always -ai, -as, -a, -ons, -ez, -ont."},
        {type:"fb",opts:["fera","fait","a fait","faisait"],hint:"It will be nice tomorrow. Faire -> fer- + -a.",s:"Il {1} beau demain. (faire, weather)",a:"fera"},
        {type:"mc",q:"'Nous ___ tout pour t'aider.' (faire, futur simple)",opts:["Fairons","Ferons","Faisons","Avons fait"],ans:"Ferons",hint:"Irregular stem fer- plus the nous ending."}
  ]},
  {id:"fre14l4",title:"Proche ou simple?",icon:"🤔",xp:15,board:true,steps:[
        {type:"intro",title:"When to use which future",desc:"Both express future events, but they're used differently. Futur proche for near/certain plans, futur simple for distant/formal/predicted events. In speech, futur proche dominates.",goals:["Choose the right future for context","Recognize register differences","Mix both naturally"]},
        {type:"tip",title:"Choosing the right future",text:"FUTUR PROCHE (aller + infinitive):\nNear future, plans, intentions\nJe vais manger. (I'm going to eat.)\nSpoken French, casual register\n\nFUTUR SIMPLE (one word):\nFormal predictions, promises\nIl pleuvra demain. (It will rain.)\nWritten French, official register\nAlso: distant future events\n\nIn daily conversation, French people\nuse futur proche ~80% of the time.\nFutur simple is more literary/formal."},
        {type:"teach",trg:"Je vais t'appeler ce soir.",src:"I'm going to call you tonight.",pos:"verb",gender:null,phonetic:"zhuh vay tah-play suh SWAHR",note:"Futur proche for a planned action.\nNear future + intention.\nVery natural in conversation.",example:"A: On peut parler plus tard?\nB: Oui, je vais t'appeler ce soir.\nA: D'accord, à ce soir!",exampleSrc:"A: Can we talk later?\nB: Yes, I'm going to call you tonight.\nA: OK, see you tonight!",funFact:"I will call you tonight. Object pronoun t' before infinitive in near-future."},
        {type:"teach",trg:"Un jour, je voyagerai autour du monde.",src:"One day, I will travel around the world.",pos:"noun",gender:"m",phonetic:"uhn zhoor zhuh vwah-yah-zhuh-RAY oh-TOOR dew MOHND",note:"Futur simple for a distant dream.\nUn jour = one day (far future).\nMore literary/aspirational tone.",example:"A: Quel est ton rêve?\nB: Un jour, je voyagerai autour du monde.\nA: C'est un beau rêve!",exampleSrc:"A: What is your dream?\nB: One day, I will travel around the world.\nA: That's a beautiful dream!",funFact:"One day, I will travel around the world. Simple future + autour de (around)."},
        {type:"mc",q:"For a plan you're doing in 5 minutes, use:",opts:["Futur proche","Futur simple","Passé composé","Imparfait"],ans:"Futur proche",hint:"Very near, definite plans = aller + infinitive."},
        {type:"fb",opts:["vais","irai","suis allé","allais"],hint:"I'm going to pick you up. Near plan, conversational.",s:"Demain, je {1} te chercher à la gare. (aller, futur proche)",a:"vais"},
        {type:"mc",q:"A weather forecast on TV would say:",opts:["Il va pleuvoir","Il pleuvra","Il pleut","Il a plu"],ans:"Il pleuvra",hint:"Formal prediction, official register = which future?"},
        {type:"fb",opts:["sauras","vas savoir","sais","savais"],hint:"One day, you will know. Distant future = futur simple.",s:"Un jour, tu {1} la vérité. (savoir, futur simple)",a:"sauras"},
        {type:"match",pairs:[{trg:"Je vais manger",src:"near plan (proche)"},{trg:"Je mangerai",src:"formal/distant (simple)"},{trg:"On va partir",src:"near plan (proche)"},{trg:"Il fera beau",src:"prediction (simple)"}]},
        {type:"mc",q:"In everyday spoken French, which is used ~80% of the time?",opts:["Futur simple","Both equally","Futur proche","Neither"],ans:"Futur proche",hint:"Casual spoken French heavily favors aller + infinitive."},
        {type:"fb",opts:["sera","va être","est","était"],hint:"It will be magnificent! Prediction with emotion.",s:"Ce {1} magnifique! (être, futur simple: prediction)",a:"sera"},
        {type:"mc",q:"A promise: 'Je te le ___!' (promettre)",opts:["Vais promettre","Promettais","Promets","Promettrai"],ans:"Promettrai",hint:"Formal promises often use the simple future for solemnity."},
        {type:"fb",opts:["vas","tomberas","es tombé","tombais"],hint:"Watch out, you're about to fall! Immediate warning.",s:"Attention, tu {1} tomber! (aller, futur proche: imminent)",a:"vas"},
        {type:"match",pairs:[{trg:"imminent action",src:"futur proche"},{trg:"formal prediction",src:"futur simple"},{trg:"spoken French plan",src:"futur proche"},{trg:"promise or resolution",src:"futur simple"}]},
        {type:"mc",q:"'Quand je ___ grand, je ___ astronaute.' (être x2, child's dream)",opts:["serai / serai","vais être / vais être","suis / suis","serais / serais"],ans:"serai / serai",hint:"A child's distant dream about growing up. Which future?"},
        {type:"fb",opts:["allons","dînerons","avons dîné","dînions"],hint:"We're going to have dinner together Saturday. Confirmed plan.",s:"Nous {1} dîner ensemble samedi. (aller, futur proche: plan)",a:"allons"},
        {type:"mc",q:"'Si tu étudies, tu ___ l'examen.' (réussir, promise/prediction)",opts:["Vas réussir","Réussiras","As réussi","Réussissais"],ans:"Réussiras",hint:"If you study, you will pass. Prediction linked to a condition."},
        {type:"fb",opts:["va arriver","arrivera","est arrivée","arrivait"],hint:"She's going to arrive soon! Imminent = aller + infinitive.",s:"Elle {1} bientôt! (arriver, futur proche: very soon)",a:"va arriver"}
  ]},
  {id:"fre14l5",title:"Quand + futur",icon:"📅",xp:15,board:true,steps:[
        {type:"intro",title:"When + future in French",desc:"Major difference from English! After 'quand' (when), French uses the future tense, NOT the present. 'When I arrive' = 'Quand j'arriverai' (not quand j'arrive).",goals:["Use futur after quand/lorsque/dès que","Avoid the English trap of present tense","Build when-clauses correctly"]},
        {type:"tip",title:"Quand + futur rule",text:"ENGLISH: When I arrive, I WILL call you.\n(present + future)\n\nFRENCH: Quand j'arriverai, je t'appellerai.\n(future + future)\n\nFrench uses FUTURE in BOTH clauses!\nThis is a major difference from English.\n\nSame rule with:\nlorsque (when, formal)\ndès que (as soon as)\naprès que (after)\ntant que (as long as)"},
        {type:"teach",trg:"Quand j'arriverai, je t'appellerai.",src:"When I arrive, I'll call you.",pos:"intj",gender:null,phonetic:"kahn zhah-ree-vuh-RAY zhuh tah-pell-RAY",note:"Both clauses use futur simple.\nQuand j'arriverai (future, not present).\nKey difference from English!",example:"A: Tu m'appelles en arrivant?\nB: Oui, quand j'arriverai, je t'appellerai.\nA: D'accord, à plus tard!",exampleSrc:"A: Will you call me when you arrive?\nB: Yes, when I arrive, I'll call you.\nA: OK, talk to you later!",funFact:"When I arrive, I'll call you. Both verbs in future after 'quand' (contrast with English)."},
        {type:"teach",trg:"Dès que tu seras prêt, on partira.",src:"As soon as you're ready, we'll leave.",pos:"intj",gender:null,phonetic:"day kuh tew suh-RAH PREH on par-tee-RAH",note:"Dès que = as soon as.\nAlso takes future in French.\nSeras = futur simple of être.",example:"A: On part quand?\nB: Dès que tu seras prêt, on partira.\nA: Je me dépêche!",exampleSrc:"A: When are we leaving?\nB: As soon as you're ready, we'll leave.\nA: I'll hurry!",funFact:"As soon as you're ready, we'll leave. Dès que + future + future."},
        {type:"mc",q:"In French: 'Quand il ___' (arrive, future event):",opts:["Arrivera","Arrive","Est arrivé","Arrivait"],ans:"Arrivera",hint:"After quand, French requires the future tense, not present."},
        {type:"fb",opts:["arriveras","arrives","es arrivé","arrivais"],hint:"When you arrive, call me. Future after quand in French.",s:"Quand tu {1}, appelle-moi. (arriver, futur simple)",a:"arriveras"},
        {type:"mc",q:"English says 'When I AM older...' French says:",opts:["Quand je suis plus âgé...","Quand je serai plus âgé...","Quand j'étais plus âgé...","Quand j'ai été plus âgé..."],ans:"Quand je serai plus âgé...",hint:"Future event after ___ = future tense in French."},
        {type:"fb",opts:["fera","fait","a fait","faisait"],hint:"As soon as it's nice out, we'll go. Future after dès que.",s:"Dès qu'il {1} beau, nous irons à la plage. (faire, future)",a:"fera"},
        {type:"match",pairs:[{trg:"quand + futur",src:"when (future event)"},{trg:"dès que + futur",src:"as soon as"},{trg:"lorsque + futur",src:"when (formal)"},{trg:"tant que + futur",src:"as long as"}]},
        {type:"mc",q:"'___ je finirai ce livre, je te le prêterai.' (when)",opts:["Si","Parce que","Quand","Pendant que"],ans:"Quand",hint:"When I finish... = temporal conjunction + future."},
        {type:"fb",opts:["seras","es","as été","étais"],hint:"As long as you will be there. Future after tant que.",s:"Tant que tu {1} là, je serai content. (être, future)",a:"seras"},
        {type:"mc",q:"Why does French use future after quand but English doesn't?",opts:["French is wrong","Only formal French does this","English used to do it too","Different grammar rules for temporal clauses"],ans:"Different grammar rules for temporal clauses",hint:"Each language has its own ___ for tense in time ___."},
        {type:"fb",opts:["ira","va","est allée","allait"],hint:"When she goes to France. Formal quand = lorsque + future.",s:"Lorsqu'elle {1} en France, elle visitera Paris. (aller, future)",a:"ira"},
        {type:"match",pairs:[
          {trg:"When I arrive (EN)",src:"present tense"},
          {trg:"Quand j'arriverai (FR)",src:"future tense"},
          {trg:"As soon as she calls (EN)",src:"present tense"},
          {trg:"Dès qu'elle appellera (FR)",src:"future tense"}
        ]},
        {type:"mc",q:"Complete: 'Quand nous ___ le temps, nous ___ au musée.'",opts:["aurons / irons","avons / allons","avions / allions","avons / irons"],ans:"aurons / irons",hint:"Both clauses in the future. Avoir and aller."},
        {type:"fb",opts:["finira","finit","a fini","finissait"],hint:"When he finishes working. Future after quand.",s:"Quand il {1} de travailler, il ira au sport. (finir, future)",a:"finira"},
        {type:"mc",q:"This rule (future after quand) applies to:",opts:["Only quand","Quand, lorsque, dès que, tant que, après que","All conjunctions","Only dès que"],ans:"Quand, lorsque, dès que, tant que, après que",hint:"All temporal conjunctions referring to future events."},
        {type:"fb",opts:["auras","as","avais","aies"],hint:"After you will have eaten. Future after après que.",s:"Après que tu {1} mangé, on sortira. (avoir, futur antérieur)",a:"auras"}
  ]},
  {id:"fre14l6",title:"Projets et prédictions",icon:"🗓️",xp:15,board:true,steps:[
        {type:"intro",title:"Talking about plans and predictions",desc:"Use both future tenses to talk about your plans, make predictions, and discuss what life will be like. Practice in realistic contexts.",goals:["Describe weekend/vacation plans","Make predictions about the future","Mix futur proche and simple naturally"]},
        {type:"teach",trg:"Ce week-end, je vais me reposer.",src:"This weekend, I'm going to rest.",pos:"verb",gender:null,phonetic:"suh week-END zhuh vay muh ruh-poh-ZAY",note:"Futur proche for weekend plans.\nSe reposer = reflexive verb.\nVais + me reposer (pronoun before infinitive).",example:"A: Tu as des projets pour le week-end?\nB: Ce week-end, je vais me reposer.\nA: Tu en as besoin!",exampleSrc:"A: Do you have plans for the weekend?\nB: This weekend, I'm going to rest.\nA: You need it!",funFact:"This weekend, I am going to rest. Reflexive verb in near-future. Me reposer."},
        {type:"teach",trg:"Dans dix ans, je vivrai à l'étranger.",src:"In ten years, I will live abroad.",pos:"intj",gender:null,phonetic:"dahn dee ZAHN zhuh vee-VRAY ah lay-trahn-ZHAY",note:"Futur simple for distant plans.\nVivre -> vivr- (drop -e) + -ai.\nÀ l'étranger = abroad.",example:"A: Où tu te vois dans dix ans?\nB: Dans dix ans, je vivrai à l'étranger.\nA: Dans quel pays?",exampleSrc:"A: Where do you see yourself in ten years?\nB: In ten years, I'll live abroad.\nA: In which country?",funFact:"In ten years, I'll live abroad. Dans + duration = in (future time)."},
        {type:"mc",q:"This weekend plans use:",opts:["Futur proche","Futur simple","Passé composé","Imparfait"],ans:"Futur proche",hint:"Near, concrete plans = aller + infinitive."},
        {type:"fb",opts:["va aller","ira","est allé","allait"],hint:"Tomorrow, we're going to a restaurant. Near plan.",s:"Demain, on {1} au restaurant. (aller, futur proche)",a:"va aller"},
        {type:"mc",q:"A fortune teller says: 'Vous ___ un grand voyage.' (faire)",opts:["Allez faire","Ferez","Avez fait","Faisiez"],ans:"Ferez",hint:"Predictions about fate/destiny use the more dramatic future."},
        {type:"fb",opts:["achèterons","allons acheter","avons acheté","achetions"],hint:"Next year, we will buy a house. Formal plan for next year.",s:"L'année prochaine, nous {1} une maison. (acheter, futur simple)",a:"achèterons"},
        {type:"match",pairs:[
          {trg:"Ce soir, je vais...",src:"tonight's plan (proche)"},
          {trg:"Un jour, je serai...",src:"distant dream (simple)"},
          {trg:"Demain, on va...",src:"tomorrow's plan (proche)"},
          {trg:"En 2030, il y aura...",src:"prediction (simple)"}
        ]},
        {type:"mc",q:"'Cet été, nous ___ en Espagne.' (voyager, vacation plan)",opts:["Avons voyagé","Voyagerons","Allons voyager","Voyagions"],ans:"Allons voyager",hint:"Summer vacation plan = near-ish, concrete = futur proche."},
        {type:"fb",opts:["pense","pensera","ira","va aller"],hint:"The main clause uses present tense; the prediction about the future uses futur simple.",s:"Je {1} que tout ___ bien. (think / go: present + futur simple)",a:["pense","ira"]},
        {type:"mc",q:"At a New Year's party, resolutions use:",opts:["Futur proche only","Present","Passé composé","Futur simple typically"],ans:"Futur simple typically",hint:"I will exercise more, I will eat better = formal resolutions."},
        {type:"fb",opts:["va","verra","a regardé","regardait"],hint:"Tonight, we're going to watch a film. Immediate plan.",s:"Ce soir, on {1} regarder un film. (going to)",a:"va"},
        {type:"match",pairs:[{trg:"Je vais partir",src:"I'm leaving (soon)"},{trg:"Je partirai",src:"I will leave (someday)"},{trg:"On va manger",src:"We're eating (now-ish)"},{trg:"On mangera",src:"We'll eat (later/formal)"}]},
        {type:"mc",q:"Mixing both: 'Ce soir je ___ manger tôt parce que demain je ___ me lever à 5h.'",opts:["vais / devrai","mangerai / vais","vais / vais","mangerai / devrai"],ans:"vais / devrai",hint:"Tonight's plan (proche) + tomorrow's obligation (simple)."},
        {type:"fb",opts:["changera","va changer","a changé","changeait"],hint:"Technology will change a lot. General prediction.",s:"La technologie {1} beaucoup dans les prochaines années. (changer, prediction)",a:"changera"},
        {type:"mc",q:"'Qu'est-ce que tu ___ faire ce week-end?' (plan question)",opts:["Feras","Vas","As fait","Faisais"],ans:"Vas",hint:"What are you going to do? Asking about near plans."},
        {type:"fb",opts:["vais écouter","écouterai","ai écouté","écoutais"],hint:"I'm going to listen to music tonight. Evening plan.",s:"Je {1} certainement de la musique ce soir. (écouter, plan)",a:"vais écouter"},
        {type:"mc",q:"Which best completes: 'Dans 50 ans, les robots ___.'",opts:["Vont tout faire","Font tout","Feront tout","Faisaient tout"],ans:"Feront tout",hint:"50 years from now = very distant future prediction."}
  ]},
  {id:"fre14l7",title:"Promesses et conditions",icon:"🤝",xp:15,board:true,steps:[
        {type:"intro",title:"Promises, conditions, and warnings",desc:"The future tense is essential for promises, warnings, and si (if) conditions. Learn the critical rule: si + present, main clause = future.",goals:["Make promises with futur simple","Use si + present / future pattern","Express warnings about consequences"]},
        {type:"tip",title:"Si + present = future",text:"In French, si (if) clauses use PRESENT TENSE.\nThe result clause uses FUTURE.\n\nSi tu étudies, tu réussiras.\n(If you study, you will pass.)\n\nSi il pleut, nous resterons à la maison.\n(If it rains, we'll stay home.)\n\nNEVER: Si tu étudieras... (si + future = wrong!)\nSi is NEVER followed by futur simple.\n\nNote: si + il = s'il (contraction)"},
        {type:"teach",trg:"Si tu veux, je t'aiderai.",src:"If you want, I'll help you.",pos:"intj",gender:null,phonetic:"see tew VUH zhuh tay-duh-RAY",note:"Si + present (veux) = condition.\nFutur simple (aiderai) = result.\nNever put futur after si!",example:"A: J'ai un problème avec mon ordinateur.\nB: Si tu veux, je t'aiderai après le travail.\nA: Ce serait super!",exampleSrc:"A: I have a problem with my computer.\nB: If you want, I'll help you after work.\nA: That would be great!",funFact:"If you want, I'll help. Type-1 conditional reinforced."},
        {type:"teach",trg:"Je te promets que je reviendrai.",src:"I promise you I'll come back.",pos:"verb",gender:null,phonetic:"zhuh tuh proh-MAY kuh zhuh ruh-vee-EN-dray",note:"Promises use futur simple.\nRevenir -> reviendr- + -ai.\nJe te promets que + futur.",example:"A: Tu pars pour longtemps?\nB: Oui, mais je te promets que je reviendrai.\nA: Tu me manqueras.",exampleSrc:"A: Are you leaving for a long time?\nB: Yes, but I promise you I'll come back.\nA: I'll miss you.",funFact:"I promise you I will come back. Present + future. Reviendrai irregular future of revenir."},
        {type:"mc",q:"'Si il pleut, nous ___ à la maison.' (rester)",opts:["Resterons","Restons","Allons rester","Restions"],ans:"Resterons",hint:"Si + present, result clause = futur simple."},
        {type:"fb",opts:["fait","fera","a fait","faisait"],hint:"If the weather is nice. After si, always use present, not future.",s:"S'il {1} beau, on ira au parc. (faire, present after si)",a:"fait"},
        {type:"mc",q:"Which is INCORRECT?",opts:["Si tu viens, je serai content","Si tu viendras, je serai content","Si tu veux, on ira au cinéma","Si elle part, je partirai aussi"],ans:"Si tu viendras, je serai content",hint:"Never use futur after si. The condition clause must be in present."},
        {type:"fb",opts:["écoutes","écouteras","as écouté","écoutais"],hint:"If you listen, you'll understand. Present after si.",s:"Si tu {1}, tu comprendras. (écouter, present)",a:"écoutes"},
        {type:"match",pairs:[{trg:"Si tu étudies...",src:"...tu réussiras"},{trg:"Si il pleut...",src:"...on restera"},{trg:"Si tu veux...",src:"...je t'aiderai"},{trg:"Si elle vient...",src:"...on sera contents"}]},
        {type:"mc",q:"A warning: 'Si tu ne fais pas attention, tu ___!' (tomber)",opts:["Tombes","Es tombé","Tomberas","Tombais"],ans:"Tomberas",hint:"Warning about future consequence. Result clause = futur."},
        {type:"fb",opts:["partons","partirons","sommes partis","partions"],hint:"If we leave early. Present after si.",s:"Si nous {1} tôt, nous arriverons à l'heure. (partir, present)",a:"partons"},
        {type:"mc",q:"'Je te ___ que tout ira bien.' (promise)",opts:["Promettais","Promettrai","Ai promis","Promets"],ans:"Promets",hint:"I promise you = present tense (the act of promising is now)."},
        {type:"fb",opts:["a","aura","avait","a eu"],hint:"If there is a problem. Present tense after si.",s:"S'il y {1} un problème, appelle-moi. (avoir, present)",a:"a"},
        {type:"match",pairs:[{trg:"Si + present",src:"condition (IF)"},{trg:"Futur simple",src:"result (THEN)"},{trg:"Si + futur",src:"NEVER correct!"},{trg:"Je promets + futur",src:"promise formula"}]},
        {type:"mc",q:"'S'il' is a contraction of:",opts:["Si + il","Se + il","Sa + il","Son + il"],ans:"Si + il",hint:"Si before il contracts. But: si + elle stays separate."},
        {type:"fb",opts:["auras","as","avais","aies"],hint:"If you don't eat, you'll be hungry. Future consequence.",s:"Si tu ne manges pas, tu {1} faim plus tard. (avoir, consequence)",a:"auras"},
        {type:"mc",q:"Summary: the si + future rule says:",opts:["Always use future after si","Never use futur simple after si","Only use futur proche after si","Use any tense after si"],ans:"Never use futur simple after si",hint:"Si takes present. The OTHER cla___ gets ___e."},
        {type:"fb",opts:["êtes","serez","recevrez","recevez"],hint:"If you are good, you will receive a gift. Present + future.",s:"Si vous {1} gentils, vous ___ un cadeau. (être/recevoir, present/future)",a:["êtes","recevrez"]}
  ]},
  {id:"fre14l8",title:"Révision du futur",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Future tense mastery",desc:"Review everything: futur proche, futur simple (regular + irregular), quand + future, si + present/future, plans, predictions, and promises.",goals:["Choose the right future in any context","Use irregular stems confidently","Apply quand and si rules correctly"]},
        {type:"tip",title:"Future tense summary",text:"FUTUR PROCHE: aller + infinitive\nNear plans, spoken French, intentions\nJe vais manger.\n\nFUTUR SIMPLE: stem + endings\nPredictions, promises, formal\nJe mangerai.\n\nQUAND RULE: quand + futur, main clause futur\nQuand j'arriverai, je t'appellerai.\n\nSI RULE: si + present, main clause futur\nSi tu veux, je viendrai.\n\nNever: si + futur simple!"},
        {type:"mc",q:"Tonight's plan: 'Ce soir, je ___.' (manger, near plan)",opts:["Vais manger","Mangerai","Mange","Ai mangé"],ans:"Vais manger",hint:"Near, concrete plan = aller + infinitive."},
        {type:"fb",opts:["vivrons","allons vivre","vivons","avons vécu"],hint:"In twenty years. Distant prediction = futur simple.",s:"Dans vingt ans, nous {1} peut-être sur Mars. (vivre, distant prediction)",a:"vivrons"},
        {type:"mc",q:"'Si elle ___, on sortira.' (venir, condition)",opts:["Viendra","Vient","Est venue","Venait"],ans:"Vient",hint:"After si, never the future. Use present tense."},
        {type:"fb",opts:["seras","es","as été","étais"],hint:"When you're big. After quand, French uses the future tense.",s:"Quand tu {1} grand, tu comprendras. (être, after quand)",a:"seras"},
        {type:"match",pairs:[{trg:"Je vais partir",src:"I'm going to leave"},{trg:"Je partirai",src:"I will leave"},{trg:"Si je pars...",src:"If I leave... (present)"},{trg:"Quand je partirai...",src:"When I leave... (future)"}]},
        {type:"mc",q:"Irregular stem: 'Nous ___ en avance.' (être)",opts:["Étions","Sommes","Serons","Avons été"],ans:"Serons",hint:"Être has an irregular stem. Add the nous ending to it."},
        {type:"fb",opts:["seras","es","apprendras","apprends"],hint:"You will be happy when you learn the news. Both future.",s:"Tu {1} content quand tu ___ la nouvelle. (être / apprendre, future)",a:["seras","apprendras"]},
        {type:"mc",q:"A promise: 'Je ne t'___ jamais.' (oublier, futur simple)",opts:["Oubliais","Oublie","Ai oublié","Oublierai"],ans:"Oublierai",hint:"I will never forget you. Promise = futur simple."},
        {type:"fb",opts:["fait","fera","ira","va aller"],hint:"If it's nice, we'll go. Si + present, result + future.",s:"S'il {1} beau demain, on ___ à la plage. (faire / aller)",a:["fait","ira"]},
        {type:"match",pairs:[{trg:"être -> ser-",src:"je serai"},{trg:"avoir -> aur-",src:"j'aurai"},{trg:"faire -> fer-",src:"je ferai"},{trg:"aller -> ir-",src:"j'irai"}]},
        {type:"mc",q:"'Dès que j'___ le temps, je t'appellerai.' (avoir)",opts:["Aurai","Ai","Avais","Aie"],ans:"Aurai",hint:"As soon as I have time. After dès que = future."},
        {type:"fb",opts:["devra","doit","a dû","devait"],hint:"He will have to answer us. Devoir -> devr- + -a.",s:"Il {1} nous répondre la semaine prochaine. (devoir, futur simple)",a:"devra"},
        {type:"mc",q:"Which mixes both futures naturally?",opts:["Je partirai et je vais revenir","Je vais partir et je reviendrai","Je vais partir et je vais revenir","Je partirai et je reviendrai"],ans:"Je vais partir et je reviendrai",hint:"Near action (going to leave) + distant promise (will come back)."},
        {type:"fb",opts:["saurez","savez","avez su","saviez"],hint:"You will know all the details soon. Savoir -> saur-.",s:"Vous {1} tous les détails bientôt. (savoir, futur simple)",a:"saurez"},
        {type:"mc",q:"You've mastered the French future! The key insight is:",opts:["Only one future tense exists","Future = past","French has two future systems with different uses","French never uses future tense"],ans:"French has two future systems with different uses",hint:"Futur proche for near/spoken, futur simple for formal/distant."},
        {type:"fb",opts:["serons","sommes","visiterons","visitons"],hint:"When we're in France, we'll visit the Louvre. Both future.",s:"Quand nous {1} en France, nous ___ le Louvre. (être / visiter, future)",a:["serons","visiterons"]}
  ]},
  {id:"fre14l8b",title:"La Nature et la Météo",icon:"⛈️",xp:15,board:true,steps:[
        {type:"intro",title:"La Nature et la Météo",desc:"Learn vocabulary for nature and weather phenomena in French.",goals:["Learn 14 nature and weather words","Use il fait/il y a for weather","Describe landscapes and weather conditions"]},
        {type:"teach",trg:"le vent",src:"the wind",pos:"noun",gender:"m",phonetic:"luh VON",note:"le vent: masculine noun.\nil fait du vent: it is windy.",example:"A: Il fait du vent aujourd'hui.\nB: Oui, c'est très fort.\nA: Prends ta veste.\nB: Bonne idée.",exampleSrc:"A: It is windy today.\nB: Yes, it is very strong.\nA: Take your jacket.\nB: Good idea.",funFact:"The wind. Latin 'ventus.' Same root as English 'vent.'"},
        {type:"teach",trg:"le nuage",src:"the cloud",pos:"noun",gender:"m",phonetic:"luh noo-AZSH",note:"le nuage: masculine noun.\nil y a des nuages: it is cloudy.",example:"A: Regarde les nuages.\nB: Ils sont gris, il va pleuvoir.\nA: On rentre à la maison ?\nB: Oui, dépêche-toi !",exampleSrc:"A: Look at the clouds.\nB: They are grey, it is going to rain.\nA: Shall we go home?\nB: Yes, hurry up!",funFact:"The cloud. Masculine (-age). From Latin 'nubes.'"},
        {type:"teach",trg:"le brouillard",src:"the fog",pos:"noun",gender:"m",phonetic:"luh broo-YAR",note:"le brouillard: masculine noun.\nil y a du brouillard: it is foggy.",example:"A: Il y a du brouillard ce matin.\nB: Oui, on ne voit rien.\nA: Conduis doucement.\nB: D'accord, je fais attention.",exampleSrc:"A: There is fog this morning.\nB: Yes, we can't see anything.\nA: Drive slowly.\nB: Okay, I'll be careful.",funFact:"Fog. From 'brouiller' (to blur). The -ard suffix often pejorative."},
        {type:"teach",trg:"l'orage",src:"the storm (m)",pos:"noun",gender:"m",phonetic:"lo-RAZSH",note:"l'orage: masculine noun.\nil y a un orage: there is a storm.",example:"A: Il y a un orage ce soir.\nB: J'entends le tonnerre.\nA: Ferme les fenêtres !\nB: C'est fait.",exampleSrc:"A: There is a storm tonight.\nB: I hear the thunder.\nA: Close the windows!\nB: Done.",funFact:"The storm. Masculine (-age). Latin 'aura' root. Weather vocabulary."},
        {type:"teach",trg:"le tonnerre",src:"the thunder",pos:"noun",gender:"m",phonetic:"luh to-NEHR",note:"le tonnerre: masculine noun.\nExpression: un coup de tonnerre.",example:"A: Tu entends le tonnerre ?\nB: Oui, c'est très fort.\nA: L'orage approche.\nB: J'ai un peu peur.",exampleSrc:"A: Do you hear the thunder?\nB: Yes, it is very loud.\nA: The storm is approaching.\nB: I am a little scared.",funFact:"Thunder. Latin 'tonitrus.' Same root as English 'thunder' via Germanic."},
        {type:"teach",trg:"l'éclair",src:"the lightning (m)",pos:"verb",gender:null,phonetic:"lay-KLEHR",note:"l'éclair: masculine noun.\nAlso means éclair (the pastry)!",example:"A: Tu as vu l'éclair ?\nB: Oui, c'était impressionnant !\nA: Il a illuminé tout le ciel.\nB: L'orage est tout près.",exampleSrc:"A: Did you see the lightning?\nB: Yes, it was impressive!\nA: It lit up the whole sky.\nB: The storm is very close.",funFact:"The lightning (m). NOT a verb; masculine noun. Also: éclair pastry!"},
        {type:"teach",trg:"l'arc-en-ciel",src:"the rainbow (m)",pos:"noun",gender:"m",phonetic:"lark-on-SYEL",note:"l'arc-en-ciel: masculine noun.\nPlural: les arcs-en-ciel.",example:"A: Regarde, un arc-en-ciel !\nB: Oh, il est magnifique.\nA: Il a sept couleurs.\nB: J'adore les arcs-en-ciel.",exampleSrc:"A: Look, a rainbow!\nB: Oh, it is magnificent.\nA: It has seven colors.\nB: I love rainbows.",funFact:"The rainbow. Masculine. Literally 'arc in sky.' Transparent compound."},
        {type:"teach",trg:"la montagne",src:"the mountain",pos:"noun",gender:"f",phonetic:"la mon-TA-nyuh",note:"la montagne: feminine noun.\nà la montagne: in the mountains.",example:"A: Tu aimes la montagne ?\nB: Oui, j'adore faire de la randonnée.\nA: Les Alpes sont magnifiques.\nB: On y va cet été ?",exampleSrc:"A: Do you like the mountains?\nB: Yes, I love hiking.\nA: The Alps are magnificent.\nB: Shall we go this summer?",funFact:"Cognate with English 'mountain'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"la rivière / le fleuve",src:"the river",pos:"noun",gender:"f",phonetic:"la ree-VYEHR / luh FLUV",note:"la rivière: smaller river (tributary).\nle fleuve: river flowing to the sea.",example:"A: Il y a une rivière près d'ici.\nB: Oui, on peut se promener au bord.\nA: La Seine est un fleuve.\nB: Le plus célèbre de France.",exampleSrc:"A: There is a river nearby.\nB: Yes, we can walk along it.\nA: The Seine is a major river.\nB: The most famous in France.",funFact:"The river. 'Rivière' feminine, flows into another river. 'Fleuve' masculine, flows into the sea. French distinguishes."},
        {type:"teach",trg:"la mer",src:"the sea",pos:"noun",gender:"f",phonetic:"la MEHR",note:"la mer: feminine noun.\nau bord de la mer: at the seaside.",example:"A: Tu préfères la mer ou la montagne ?\nB: La mer, j'adore la plage.\nA: On va à la mer cet été.\nB: Super, j'ai hâte !",exampleSrc:"A: Do you prefer the sea or the mountains?\nB: The sea, I love the beach.\nA: We are going to the sea this summer.\nB: Great, I can't wait!",funFact:"The sea. Feminine. Same root as Latin 'mare.' Silent r."},
        {type:"teach",trg:"le lac",src:"the lake",pos:"noun",gender:"m",phonetic:"luh LAK",note:"le lac: masculine noun.\nau bord du lac: at the lakeside.",example:"A: Le lac est très calme aujourd'hui.\nB: Oui, parfait pour une promenade.\nA: On peut faire du bateau.\nB: Bonne idée !",exampleSrc:"A: The lake is very calm today.\nB: Yes, perfect for a walk.\nA: We can go boating.\nB: Good idea!",funFact:"The lake. Latin 'lacus.' Same root as English 'lake.'"},
        {type:"teach",trg:"la forêt",src:"the forest",pos:"noun",gender:"f",phonetic:"la fo-RAY",note:"la forêt: feminine noun.\nen forêt: in the forest.",example:"A: Allons nous promener dans la forêt.\nB: D'accord, il fait frais sous les arbres.\nA: J'adore le calme de la forêt.\nB: Moi aussi.",exampleSrc:"A: Let's take a walk in the forest.\nB: Okay, it is cool under the trees.\nA: I love the calm of the forest.\nB: Me too.",funFact:"Cognate with English 'forest'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"la fleur",src:"the flower",pos:"noun",gender:"f",phonetic:"la FLUR",note:"la fleur: feminine noun.\nun bouquet de fleurs: a bouquet.",example:"A: Les fleurs sont belles au printemps.\nB: Oui, j'aime les roses.\nA: Moi, je préfère les tulipes.\nB: Allons au jardin botanique.",exampleSrc:"A: The flowers are beautiful in spring.\nB: Yes, I like roses.\nA: I prefer tulips.\nB: Let's go to the botanical garden.",funFact:"The flower. Feminine. Latin 'florem.' Same root as English 'flora,' 'flourish.'"},
        {type:"teach",trg:"l'arbre",src:"the tree (m)",pos:"verb",gender:null,phonetic:"LAR-bruh",note:"l'arbre: masculine noun.\nPlural: les arbres.",example:"A: Cet arbre est énorme !\nB: Oui, il a plus de cent ans.\nA: Il y a beaucoup d'arbres dans le parc.\nB: C'est très vert ici.",exampleSrc:"A: This tree is enormous!\nB: Yes, it is over a hundred years old.\nA: There are many trees in the park.\nB: It is very green here.",funFact:"The tree (m). NOT a verb; masculine noun from Latin 'arbor.'"},
        {type:"tip",title:"Parler de la météo",deepDive:{
          title:"Weather structures",
          text:"French uses three main structures for weather:\n1. il fait + adjective: il fait chaud, il fait froid, il fait beau\n2. il y a + noun: il y a du vent, il y a des nuages\n3. il + verb: il pleut (rains), il neige (snows)"
        },text:"Weather expressions in French:\nil fait du vent: it is windy\nil y a des nuages: it is cloudy\nil y a du brouillard: it is foggy\nil y a un orage: there is a storm\nil fait beau: the weather is nice\nil pleut: it is raining"},
        {type:"mc",q:"How do you say 'it is windy' in French?",opts:["il fait du vent","il fait du soleil","il y a un orage","il fait froid"],ans:"il fait du vent",hint:"This expression uses faire + du + the word for wind."},
        {type:"fb",opts:["nuages","étoiles","oiseaux","arbres"],hint:"Grey masses in the sky that indicate coming rain.",s:"Il y a des {1} gris dans le ciel, il va pleuvoir.",a:["nuages"]},
        {type:"match",pairs:[{trg:"la montagne",src:"the mountain"},{trg:"la forêt",src:"the forest"},{trg:"le lac",src:"the lake"},{trg:"la mer",src:"the sea"},{trg:"la fleur",src:"the flower"}]},
        {type:"mc",q:"What is the difference between 'la rivière' and 'le fleuve'?",opts:["la rivière is bigger than le fleuve","le fleuve flows to the sea, la rivière is a tributary","They mean the same thing","le fleuve is a small stream"],ans:"le fleuve flows to the sea, la rivière is a tributary",hint:"One ___ into the ocean while the other joins a larger body of water."}
  ,{type:"match",pairs:[{trg:"le tonnerre",src:"the thunder"},{trg:"la rivière / le fleuve",src:"the river"}]}]},

  {id:"frv2_u14l_a2_transport_life",title:"Transports et santé",icon:"🚗",xp:15,board:true,steps:[
    {type:"intro",title:"Transport and Daily Life",desc:"Nine A2 verbs and nouns for transport, places, and basic health.",goals:["Use conduire and garer for driving","Describe places with l'immeuble and le bâtiment","Handle basic health: tomber malade"]},
    {type:"teach",trg:"conduire",src:"to drive",pos:"verb",gender:null,phonetic:"kon-DWEER",
     note:"Irregular -re verb.\nJe conduis, tu conduis, il conduit, nous conduisons.\nConduire une voiture = drive a car.",
     example:"A: Tu conduis?\nB: Oui, je conduis bien.",
     exampleSrc:"A: Do you drive?\nB: Yes, I drive well.",
     funFact:"Conduire shares a Latin root (conducere) with English 'conduct.' In French, you can 'conduire' a car, a train, or even a meeting, the core meaning is 'to lead.'"},
    {type:"teach",trg:"garer",src:"to park (a vehicle)",pos:"verb",gender:null,phonetic:"gah-RAY",
     note:"Regular -er verb.\nJe gare, tu gares, il gare.\nOften reflexive: se garer = to park oneself.",
     example:"A: Où est-ce que tu gares la voiture?\nB: Je gare la voiture ici.",
     exampleSrc:"A: Where do you park the car?\nB: I park the car here.",
     funFact:"Garer comes from the word 'gare' (train station), originally the place to 'park' trains. French drivers in cities often circle blocks looking for parking (du stationnement)."},
    {type:"teach",trg:"traverser",src:"to cross",pos:"verb",gender:null,phonetic:"trah-ver-SAY",
     note:"Regular -er verb.\nTraverser la rue = cross the street.\nTraverser + noun (no preposition).",
     example:"A: Je vais traverser la rue.\nB: Fais attention!",
     exampleSrc:"A: I am going to cross the street.\nB: Be careful!",
     funFact:"Traverser comes from Latin 'traversare' (to go across). French jaywalking laws are strict, always use 'passage pour piétons' (pedestrian crossing)."},
    {type:"teach",trg:"l'immeuble",src:"the apartment building",pos:"noun",gender:"m",phonetic:"lee-MURBL",
     note:"Masculine. Plural: les immeubles.\nSpecifically a residential building with apartments.",
     example:"A: Tu habites dans quel immeuble?\nB: Dans cet immeuble ici.",
     exampleSrc:"A: Which building do you live in?\nB: In this building here.",
     funFact:"Immeuble literally means 'immovable property', contrast with 'meuble' (movable furniture). French real estate law uses this Latin-origin distinction daily."},
    {type:"teach",trg:"le bâtiment",src:"the building (generic)",pos:"noun",gender:"m",phonetic:"lah bah-tee-MON",
     note:"Masculine. Plural: les bâtiments.\nGeneric building, can be any type: office, school, house.",
     example:"A: Ce bâtiment est grand.\nB: Oui, très grand.",
     exampleSrc:"A: This building is big.\nB: Yes, very big.",
     funFact:"Bâtiment comes from the verb 'bâtir' (to build). French distinguishes 'immeuble' (residential apartments) from 'bâtiment' (any building)."},
    {type:"teach",trg:"tomber malade",src:"to fall ill / get sick",pos:"verb",gender:null,phonetic:"tom-BAY mah-LAHD",
     note:"Fixed expression.\nTomber uses être in passé composé: Je suis tombé malade.\nMalade agrees with the subject.",
     example:"A: Qu'est-ce qui s'est passé?\nB: Je suis tombé malade.",
     exampleSrc:"A: What happened?\nB: I got sick.",
     funFact:"The French image of illness as 'falling' is shared with many languages (English: fell ill). In French, you 'fall' into sickness suddenly rather than 'become' sick gradually."},
    {type:"teach",trg:"tousser",src:"to cough",pos:"verb",gender:null,phonetic:"too-SAY",
     note:"Regular -er verb.\nJe tousse, tu tousses, il tousse.",
     example:"A: Tu tousses beaucoup!\nB: Oui, je suis malade.",
     exampleSrc:"A: You are coughing a lot!\nB: Yes, I am sick.",
     funFact:"Tousser is onomatopoeic, the sound 'ousse' mimics the cough itself. Pharmacies in France sell sirop contre la toux (cough syrup) over the counter."},
    {type:"teach",trg:"éternuer",src:"to sneeze",pos:"verb",gender:null,phonetic:"ay-ter-new-AY",
     note:"Regular -er verb.\nJ'éternue, tu éternues, il éternue.\nPolite response to someone sneezing: À tes souhaits!",
     example:"A: J'éternue beaucoup aujourd'hui.\nB: À tes souhaits!",
     exampleSrc:"A: I am sneezing a lot today.\nB: Bless you!",
     funFact:"À tes souhaits! (to your wishes) is what French speakers say after a sneeze, the formal version is À vos souhaits! After the second sneeze, some say À tes amours! (to your loves)."},
    {type:"teach",trg:"rencontrer",src:"to meet / encounter",pos:"verb",gender:null,phonetic:"ron-kon-TRAY",
     note:"Regular -er verb.\nJe rencontre, tu rencontres, il rencontre.\nRencontrer une personne = meet a person.",
     example:"A: J'ai rencontré un ami.\nB: Où?\nA: Dans la rue.",
     exampleSrc:"A: I met a friend.\nB: Where?\nA: In the street.",
     funFact:"Rencontrer comes from Latin 'in contra' (toward, against). French distinguishes 'rencontrer' (a chance meeting) from 'retrouver' (a planned meeting). English borrowed both senses into 'encounter.'"},
    {type:"tip",title:"être vs avoir in passé composé: tomber",
     text:"The verb tomber uses être (not avoir) in the past tense:\n\nJe suis tombé (I fell)\nJe suis tombée (if speaker is female, adds -e)\nIls sont tombés malades (They got sick)\n\nThis is true for all movement and state-change verbs. Memorize DR MRS VANDERTRAMP for the full list.",
     deepDive:{title:"Les pompiers et les urgences",
      text:"In emergencies, call 18 for pompiers (firefighters) or 15 for SAMU (medical). Les urgences (the ER) takes walk-ins in most French cities."}},
    {type:"mc",q:"Quel verbe signifie 'to drive'?",opts:["conduire","traverser","tomber","garer"],ans:"conduire",hint:"Irregular -re verb sharing Latin root with English 'conduct.'"},
    {type:"mc",q:"Quelle est la différence entre 'immeuble' et 'bâtiment'?",opts:["Ils sont synonymes","Immeuble = résidentiel, bâtiment = générique","Bâtiment est plus moderne","Immeuble est plus petit"],ans:"Immeuble = résidentiel, bâtiment = générique",hint:"One refers specifically to apartments; the other is any structure."},
    {type:"fb",opts:["tombé","rencontré","traversé","garé"],hint:"Past participle of tomber (with être). The person is now sick.",s:"Je suis {1} malade hier.",a:"tombé",sSrc:"I got sick yesterday."},
    {type:"fb",opts:["tousse","éternue","parle","regarde"],hint:"Verb for the sound you make when you have a cold, onomatopoeic.",s:"Je {1} beaucoup, je suis malade.",a:"tousse",sSrc:"I am coughing a lot, I am sick."},
    {type:"fb",opts:["gare","conduis","traverse","rencontre"],hint:"First-person of the -er verb meaning 'to park.'",s:"Je {1} la voiture devant l'immeuble.",a:"gare",sSrc:"I park the car in front of the building."},
    {type:"fb",opts:["rencontre","conduit","gare","éternue"],hint:"First-person meaning 'I meet by chance.'",s:"Je {1} mon ami dans la rue.",a:"rencontre",sSrc:"I meet my friend in the street."},
    {type:"match",pairs:[{trg:"conduire",src:"to drive"},{trg:"garer",src:"to park"},{trg:"traverser",src:"to cross"},{trg:"rencontrer",src:"to meet"}]},
    {type:"match",pairs:[{trg:"tomber malade",src:"to get sick"},{trg:"tousser",src:"to cough"},{trg:"éternuer",src:"to sneeze"},{trg:"l'immeuble",src:"apartment building"},{trg:"le bâtiment",src:"building"}]}
  ]}
]};
